1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const key = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (liveNeighbors: number): boolean =>
15	  liveNeighbors === 2 || liveNeighbors === 3;
16	
17	const isBorn = (liveNeighbors: number): boolean =>
18	  liveNeighbors === 3;
19	
20	const countLiveNeighbors = (cell: Cell, alive: Set<string>): number =>
21	  neighborsOf(cell).filter((n) => alive.has(key(n))).length;
22	
23	const deadNeighborsOf = (liveCells: Cell[], alive: Set<string>): Cell[] => {
24	  const candidates = new Map<string, Cell>();
25	  for (const cell of liveCells) {
26	    for (const neighbor of neighborsOf(cell)) {
27	      if (!alive.has(key(neighbor))) candidates.set(key(neighbor), neighbor);
28	    }
29	  }
30	  return [...candidates.values()];
31	};
32	
33	export function nextGeneration(liveCells: Cell[]): Cell[] {
34	  const alive = new Set(liveCells.map(key));
35	  const liveNeighbors = (cell: Cell) => countLiveNeighbors(cell, alive);
36	  const survivors = liveCells.filter((cell) => survives(liveNeighbors(cell)));
37	  const births = deadNeighborsOf(liveCells, alive).filter((cell) => isBorn(liveNeighbors(cell)));
38	  return [...survivors, ...births];
39	}
