1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die from underpopulation — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const sort = (cells: Cell[]) => [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
17	    expect(sort(nextGeneration(block))).toEqual(sort(block));
18	  });
19	  it("live cell with 2 neighbors survives — row of 3 [(0,0),(1,0),(2,0)], center (1,0) survives", () => {
20	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
21	    expect(result).toContainEqual([1, 0]);
22	  });
23	  it("live cell with 4 neighbors dies from overpopulation — center of plus dies", () => {
24	    const cells: Cell[] = [[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]];
25	    const result = nextGeneration(cells);
26	    expect(result).not.toContainEqual([1, 1]);
27	  });
28	  it("dead cell with exactly 3 neighbors becomes alive — (1,1) born from [(0,0),(1,0),(0,1)]", () => {
29	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
30	    expect(result).toContainEqual([1, 1]);
31	  });
32	  it("blinker oscillates: vertical [(0,0),(0,1),(0,2)] → horizontal [(-1,1),(0,1),(1,1)]", () => {
33	    const sort = (cells: Cell[]) => [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
34	    const next = nextGeneration([[0, 0], [0, 1], [0, 2]]);
35	    expect(sort(next)).toEqual(sort([[-1, 1], [0, 1], [1, 1]]));
36	  });
37	  it("handles negative coordinates correctly — block at negative origin stays stable", () => {
38	    const sort = (cells: Cell[]) => [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
39	    const block: Cell[] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
40	    expect(sort(nextGeneration(block))).toEqual(sort(block));
41	  });
42	});
