const countLiveNeighbors = (cell: Cell, alive: Set<string>): number =>
  neighborsOf(cell).filter((n) => alive.has(key(n))).length;

const deadNeighborsOf = (liveCells: Cell[], alive: Set<string>): Cell[] => {
  const candidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      if (!alive.has(key(neighbor))) candidates.set(key(neighbor), neighbor);
    }
  }
  return [...candidates.values()];
};

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const alive = new Set(liveCells.map(key));
  const liveNeighbors = (cell: Cell) => countLiveNeighbors(cell, alive);
  const survivors = liveCells.filter((cell) => survives(liveNeighbors(cell)));
  const births = deadNeighborsOf(liveCells, alive).filter((cell) => isBorn(liveNeighbors(cell)));
  return [...survivors, ...births];
}

